import{_ as a,c as l,o as e,V as i}from"./chunks/framework.9b555ede.js";const p=JSON.parse('{"title":"前端技能自查表","description":"","frontmatter":{},"headers":[],"relativePath":"note/前端技能清单.md","filePath":"note/前端技能清单.md","lastUpdated":1640536454000}'),r={name:"note/前端技能清单.md"},t=i('<h1 id="前端技能自查表" tabindex="-1">前端技能自查表 <a class="header-anchor" href="#前端技能自查表" aria-label="Permalink to &quot;前端技能自查表&quot;">​</a></h1><p>梳理下作为前端架构师应该掌握的知识技能，方便自己能一步一步的成长为架构师。 技能掌握程度自查列表</p><h3 id="css" tabindex="-1">CSS <a class="header-anchor" href="#css" aria-label="Permalink to &quot;CSS&quot;">​</a></h3><blockquote><p>推荐两本书，1.《CSS世界》、2.《CSS揭秘》 先后看完这两本书，对提升css技术有很大帮助</p></blockquote><ul><li>命名建议与约束</li><li>CSS选择器</li><li>CSS权重</li><li>浏览器的兼容性解决方案</li><li>响应式布局方案</li><li>对css渲染性能的思考</li><li>合理使用css预处理：scss、less</li><li>图片的细节处理</li><li>图标的选择</li><li>动画与交互，对用户体验的思考</li><li>CSS计算属性</li><li>tailwindcss、windicss</li></ul><p><a href="https://blog.csdn.net/kw023781/article/details/105602177" target="_blank" rel="noreferrer">看详情点我《前端技能自查——CSS》</a></p><h3 id="html" tabindex="-1">HTML <a class="header-anchor" href="#html" aria-label="Permalink to &quot;HTML&quot;">​</a></h3><ul><li><a href="https://blog.csdn.net/kw023781/article/details/108288604" target="_blank" rel="noreferrer">语义标签的意义</a></li><li>块元素、行元素、伪元素</li><li>元素自带的特殊属性</li></ul><h3 id="svg" tabindex="-1">SVG <a class="header-anchor" href="#svg" aria-label="Permalink to &quot;SVG&quot;">​</a></h3><ul><li>矢量图形的绘制</li><li>线、圆、多边形的绘制</li><li>鼠标事件的处理</li><li>图形放大缩小</li></ul><h3 id="canvas" tabindex="-1">Canvas <a class="header-anchor" href="#canvas" aria-label="Permalink to &quot;Canvas&quot;">​</a></h3><blockquote><p>这里先推荐一个canvas库，很好用的。fabricjs, <a href="http://fabricjs.com/" target="_blank" rel="noreferrer">官网</a>, <a href="https://github.com/fabricjs/fabric.js" target="_blank" rel="noreferrer">GitHub</a>, <a href="https://github.com/Rookie-Birds/Fabric-Tutorial_zh-CN" target="_blank" rel="noreferrer">中文文档</a></p></blockquote><ul><li>简单的图形绘制</li><li>像素比例，宽高、坐标计算</li><li>定时器实现动画（循环：绘制-擦除-绘制）</li><li>缓存技术，提高动画性能</li><li>鼠标交互事件</li><li>利用canvas处理图像，对二进制的操作</li><li>echarts 的实现原理</li></ul><h3 id="javascript" tabindex="-1">JavaScript <a class="header-anchor" href="#javascript" aria-label="Permalink to &quot;JavaScript&quot;">​</a></h3><ul><li>typeof instanceof toString 类型判断</li><li>this的4种写法</li><li>隐式转换 == 与 === 触发的逻辑</li><li>es6新特性的掌握情况</li><li>变量的作用域</li><li>原型链与继承的实现</li><li>对计算精度的处理（js基于二进制计算产生的精度问题）</li><li>JavaScript 编译机制（至少编译两次）</li><li>JavaScript 程序执行顺序</li><li>宏任务、微任务以及执行顺序</li><li>leetcode算法 <a href="https://blog.csdn.net/kw023781/article/details/116606906" target="_blank" rel="noreferrer">前端技能自查——JavaScript</a></li></ul><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h3><ul><li>类型推断</li><li>泛型的使用</li><li>类型的定义声明</li><li>TSC编译机制</li><li>d.ts文件的生成</li></ul><h3 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h3><ul><li>HTTP协议、TCP三次握手</li><li>HTTP响应码</li><li>跨域</li><li>request</li><li>response</li><li>cookie</li><li>session</li><li>https</li></ul><h3 id="error" tabindex="-1">Error <a class="header-anchor" href="#error" aria-label="Permalink to &quot;Error&quot;">​</a></h3><ul><li>node.js 中的错误处理</li><li>浏览器中的错误处理</li><li>vue的全局错误处理</li></ul><h3 id="cdn与dns负载均衡" tabindex="-1">CDN与DNS负载均衡 <a class="header-anchor" href="#cdn与dns负载均衡" aria-label="Permalink to &quot;CDN与DNS负载均衡&quot;">​</a></h3><ul><li>CDN配置</li><li></li></ul><h3 id="浏览器内核与加载机制" tabindex="-1">浏览器内核与加载机制 <a class="header-anchor" href="#浏览器内核与加载机制" aria-label="Permalink to &quot;浏览器内核与加载机制&quot;">​</a></h3><ul><li>一次最多6次请求限制</li><li></li></ul><h3 id="浏览器api" tabindex="-1">浏览器API <a class="header-anchor" href="#浏览器api" aria-label="Permalink to &quot;浏览器API&quot;">​</a></h3><h3 id="eslint" tabindex="-1">Eslint <a class="header-anchor" href="#eslint" aria-label="Permalink to &quot;Eslint&quot;">​</a></h3><h3 id="v8引擎" tabindex="-1">V8引擎 <a class="header-anchor" href="#v8引擎" aria-label="Permalink to &quot;V8引擎&quot;">​</a></h3><h3 id="tree-shaking" tabindex="-1">Tree Shaking <a class="header-anchor" href="#tree-shaking" aria-label="Permalink to &quot;Tree Shaking&quot;">​</a></h3><h3 id="单元测试" tabindex="-1">单元测试 <a class="header-anchor" href="#单元测试" aria-label="Permalink to &quot;单元测试&quot;">​</a></h3><ul><li>测试管理工具 karma</li><li>测试框架 Mocha、jest</li><li>断言库 sinon-chai</li><li>测试浏览器 PhantomJS、Headless Chrome</li></ul><h3 id="rollup" tabindex="-1">rollup <a class="header-anchor" href="#rollup" aria-label="Permalink to &quot;rollup&quot;">​</a></h3><h3 id="webpack" tabindex="-1">webpack <a class="header-anchor" href="#webpack" aria-label="Permalink to &quot;webpack&quot;">​</a></h3><h3 id="vite" tabindex="-1">vite <a class="header-anchor" href="#vite" aria-label="Permalink to &quot;vite&quot;">​</a></h3><h3 id="node" tabindex="-1">Node <a class="header-anchor" href="#node" aria-label="Permalink to &quot;Node&quot;">​</a></h3><h3 id="vue" tabindex="-1">Vue <a class="header-anchor" href="#vue" aria-label="Permalink to &quot;Vue&quot;">​</a></h3><h3 id="微信小程序" tabindex="-1">微信小程序 <a class="header-anchor" href="#微信小程序" aria-label="Permalink to &quot;微信小程序&quot;">​</a></h3><h3 id="react" tabindex="-1">React <a class="header-anchor" href="#react" aria-label="Permalink to &quot;React&quot;">​</a></h3><h3 id="electron-桌面应用" tabindex="-1">Electron 桌面应用 <a class="header-anchor" href="#electron-桌面应用" aria-label="Permalink to &quot;Electron 桌面应用&quot;">​</a></h3><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><h3 id="java" tabindex="-1">Java <a class="header-anchor" href="#java" aria-label="Permalink to &quot;Java&quot;">​</a></h3>',41),o=[t];function h(n,s,c,d,u,b){return e(),l("div",null,o)}const f=a(r,[["render",h]]);export{p as __pageData,f as default};
